<?php require_once __DIR__.'/../../includes/bootstrap.php'; require_login(); use app\Services\BookTypeService; $svc=new BookTypeService(); $errors=[]; $row=['name'=>'','description'=>'']; if('create'==='edit'){ $id=(int)($_GET['id']??0); $row=$svc->find($id); if(!$row) include PUBLIC_PATH.'/404.php'; } if($_SERVER['REQUEST_METHOD']==='POST'){ $r=('create'==='edit')?$svc->save($_POST,$id):$svc->save($_POST); if($r['ok']){ flash('success','Đã lưu loại sách'); redirect_to('book_types/index.php'); } $errors=$r['errors']??[]; $row=array_merge($row,$_POST); } $title='Thêm loại sách'; include ROOT_PATH.'/includes/header.php'; ?><h1 class='h3 mb-3'>Thêm loại sách</h1><div class="card"><div class="card-body"><form method="post"><div class="mb-3"><label class="form-label required">Tên loại</label><input name="name" class="form-control" value="<?= e($row['name']) ?>"><div class="text-danger small"><?= e($errors['name']??'') ?></div></div><div class="mb-3"><label class="form-label">Mô tả</label><textarea name="description" class="form-control"><?= e($row['description']) ?></textarea></div><button class="btn btn-primary">Lưu</button> <a class="btn btn-secondary" href="index.php">Quay lại</a></form></div></div><?php include ROOT_PATH.'/includes/footer.php'; ?>
